SELECT * FROM ( SELECT ROWNUM rnum, data.* FROM ( SELECT DISTINCT c.c_id, c.c_kind, c.c_name, c.c_tel, c.c_addr, c.c_info, c.c_boss FROM company c
INNER JOIN interior i ON i.c_id = c.c_id AND i.c_kind = c.c_kind AND i.c_name = c.c_name
WHERE c.c_kind = 'interior'
AND ( c.c_name LIKE '%' || #{search} || '%' OR c.c_addr LIKE '%' || #{search} || '%' OR c.c_tel LIKE '%' || #{search} || '%' )
AND i.i_tag = #{filterType} AND i.i_text = #{filterValue}
ORDER BY c.c_name ASC ) data WHERE ROWNUM <= #{end} ) WHERE rnum >= #{start}

